// HasServer applies the HasEdge predicate on the "server" edge.
func HasServer() predicate.RobotMCPTool {
	return predicate.RobotMCPTool(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ServerTable, ServerColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasServerWith applies the HasEdge predicate on the "server" edge with a given conditions (other predicates).
func HasServerWith(preds ...predicate.RobotMCPServer) predicate.RobotMCPTool {
	return predicate.RobotMCPTool(func(s *sql.Selector) {
		step := newServerStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RobotMCPTool) predicate.RobotMCPTool {
	return predicate.RobotMCPTool(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RobotMCPTool) predicate.RobotMCPTool {
	return predicate.RobotMCPTool(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RobotMCPTool) predicate.RobotMCPTool {
	return predicate.RobotMCPTool(sql.NotPredicates(p))
}
